_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  uv0 = vUv;
screen3 = vec3 ((vUv-.5)*uAspect.xy, 1-vRadius/4);

rsl = project (.5);
lprof2 = 0;
ret1 = vec3 (.1,.15,.2);
mask2 = 0;
for (n=anz; n >= 1; n--) {
//  if (q28%3 == 0) {mov = -mov/2 ;}
  dist = n-.5+q31+(q32/2); lav_gnd = 0;
  for (m=1; m <= quality; m++) {
    rsl = project (dist)+vec3 (mov,0) + n/2;
    lprof =  .5-lum(GetBlur1(fract(rsl.xy))); //mittelwert null !#
    lav_gnd -= lprof/quality*depth/rsl.z;
  }

  rsl = project (dist)+vec3 (mov,0) +n/2;
  rsl2 = project (dist)+vec3 (mov*.9,0);
  shadow = clamp01(4*GetBlur1(fract(rsl2.xy)));// * !(n == 1);
  neu = GetPixel(fract(rsl.xy));
  mask = clamp01(8*neu);
  neu *= 1-.7*lum(texture(sampler_noise_lq,rsl.xy*4));
  neu *= (1-shadow*rand_preset.z/2) ;
//  neu *= clamp01(3-abs(rsl.z)) ; // Abdunkelung hinten
//  neu = mix(0, neu, clamp01(15-rsl.z/4)); // Nebel
  ret1 = mix(ret1,neu,mask) ;
  lprof2 = mix(lprof2,lprof,mask);
  mask2 = mix(mask2,mask,mask);
}

rsl = project (dist)+vec3 (mov+lprof2/4,0);
vec2 noise = texture(sampler_noise_hq,rsl+uTime*.1).xy;
vec3 sun = ret1/length(sin(rsl.xy*16+noise));
ret1 +=  sun* (1+0*q22)*vec3(.3,.6,1);

ret = 1-exp(.1-ret1) ;

  fragColor = ret;
}
